+func verboseBenchmarkLines(value any) []string {
+	var measurement syncer.Measurement
+	var stats syncer.Stats
+	var mode string
+	var batching bool
+	var batchCount int
+
+	switch v := value.(type) {
+	case syncer.Result:
+		measurement = v.Measurement
+		stats = v.Stats
+		mode = v.RelayMode
+		batching = v.Batching
+		batchCount = v.BatchCount
+	case syncer.ProbeResult:
+		measurement = v.Measurement
+		stats = v.Stats
+		mode = "probe"
+	case syncer.FetchResult:
+		measurement = v.Measurement
+		stats = v.Stats
+		mode = "fetch"
+	default:
+		return nil
+	}
+
+	if !measurement.Enabled {
+		return nil
+	}
+
+	lines := []string{
+		fmt.Sprintf(
+			"benchmark: elapsed=%s peak-heap=%s peak-alloc=%s total-alloc=%s gc=%d",
+			formatMillis(measurement.ElapsedMillis),
+			formatBytes(measurement.PeakHeapInuseBytes),
+			formatBytes(measurement.PeakAllocBytes),
+			formatBytes(measurement.TotalAllocBytes),
+			measurement.GCCount,
+		),
+	}
+
+	if stats.Enabled {
+		var requestBytes int64
+		var responseBytes int64
+		var requests int
+		for _, item := range stats.Items {
+			requestBytes += item.RequestBytes
+			responseBytes += item.ResponseBytes
+			requests += item.Requests
+		}
+		summary := fmt.Sprintf(
+			"benchmark: requests=%d tx=%s rx=%s",
+			requests,
+			formatBytes(uint64(requestBytes)),
+			formatBytes(uint64(responseBytes)),
+		)
+		if mode != "" {
+			summary += " mode=" + mode
+		}
+		if batching {
+			summary += fmt.Sprintf(" batches=%d", batchCount)
+		}
+		lines = append(lines, summary)
+	}
+
+	return lines
+}
