func sourceRefPrefixes(cfg Config) []string {
	prefixSet := map[string]struct{}{}

	addPrefix := func(ref plumbing.ReferenceName) {
		switch {
		case ref.IsBranch():
			prefixSet["refs/heads/"] = struct{}{}
		case ref.IsTag():
			prefixSet["refs/tags/"] = struct{}{}
		}
	}

